import{_ as a,o as e,c as o,ae as r}from"./chunks/framework.C7FLYIpo.js";const g=JSON.parse('{"title":"온보딩 개요","description":"OpenClaw 온보딩 옵션 및 흐름 개요","frontmatter":{"title":"온보딩 개요","description":"OpenClaw 온보딩 옵션 및 흐름 개요"},"headers":[],"relativePath":"start/onboarding-overview.md","filePath":"start/onboarding-overview.md","lastUpdated":null}'),n={name:"start/onboarding-overview.md"};function s(d,t,i,l,c,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="온보딩-개요" tabindex="-1">온보딩 개요 <a class="header-anchor" href="#온보딩-개요" aria-label="Permalink to &quot;온보딩 개요&quot;">​</a></h1><p>OpenClaw에는 두 가지 온보딩 경로가 있습니다. 둘 다 인증, Gateway 및 선택적 채팅 채널을 구성하며 — 설정과 상호작용하는 방식만 다릅니다.</p><h2 id="어떤-경로를-사용해야-합니까" tabindex="-1">어떤 경로를 사용해야 합니까? <a class="header-anchor" href="#어떤-경로를-사용해야-합니까" aria-label="Permalink to &quot;어떤 경로를 사용해야 합니까?&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>CLI 온보딩</th><th>macOS 앱 온보딩</th></tr></thead><tbody><tr><td><strong>플랫폼</strong></td><td>macOS, Linux, Windows (네이티브 또는 WSL2)</td><td>macOS 전용</td></tr><tr><td><strong>인터페이스</strong></td><td>터미널 마법사</td><td>앱 내 안내 UI</td></tr><tr><td><strong>최적 용도</strong></td><td>서버, 헤드리스, 완전 제어</td><td>데스크톱 Mac, 시각적 설정</td></tr><tr><td><strong>자동화</strong></td><td>스크립트를 위한 <code>--non-interactive</code></td><td>수동만 가능</td></tr><tr><td><strong>명령</strong></td><td><code>openclaw onboard</code></td><td>앱 실행</td></tr></tbody></table><p>대부분의 사용자는 <strong>CLI 온보딩</strong>으로 시작해야 합니다 — 어디서나 작동하며 가장 많은 제어권을 제공합니다.</p><h2 id="온보딩이-구성하는-항목" tabindex="-1">온보딩이 구성하는 항목 <a class="header-anchor" href="#온보딩이-구성하는-항목" aria-label="Permalink to &quot;온보딩이 구성하는 항목&quot;">​</a></h2><p>어떤 경로를 선택하더라도 온보딩은 다음을 설정합니다:</p><ol><li><strong>모델 프로바이더 및 인증</strong> — 선택한 프로바이더의 API 키, OAuth 또는 설정 토큰</li><li><strong>워크스페이스</strong> — 에이전트 파일, 부트스트랩 템플릿 및 메모리를 위한 디렉토리</li><li><strong>Gateway</strong> — 포트, 바인드 주소, 인증 모드</li><li><strong>채널</strong> (선택 사항) — BlueBubbles, Discord, Feishu, Google Chat, Mattermost, Microsoft Teams, Telegram, WhatsApp 등의 내장 및 번들 채팅 채널</li><li><strong>데몬</strong> (선택 사항) — Gateway가 자동으로 시작되도록 하는 백그라운드 서비스</li></ol><h2 id="cli-온보딩" tabindex="-1">CLI 온보딩 <a class="header-anchor" href="#cli-온보딩" aria-label="Permalink to &quot;CLI 온보딩&quot;">​</a></h2><p>어떤 터미널에서든 실행:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onboard</span></span></code></pre></div><p>한 번에 백그라운드 서비스도 설치하려면 <code>--install-daemon</code>을 추가하십시오.</p><p>전체 참조: <a href="/openclaw-docs-ko/start/wizard">온보딩 (CLI)</a> CLI 명령 문서: <a href="/openclaw-docs-ko/cli/onboard"><code>openclaw onboard</code></a></p><h2 id="macos-앱-온보딩" tabindex="-1">macOS 앱 온보딩 <a class="header-anchor" href="#macos-앱-온보딩" aria-label="Permalink to &quot;macOS 앱 온보딩&quot;">​</a></h2><p>OpenClaw 앱을 엽니다. 첫 실행 마법사가 시각적 인터페이스로 동일한 단계를 안내합니다.</p><p>전체 참조: <a href="/openclaw-docs-ko/start/onboarding">온보딩 (macOS 앱)</a></p><h2 id="맞춤형-또는-목록에-없는-프로바이더" tabindex="-1">맞춤형 또는 목록에 없는 프로바이더 <a class="header-anchor" href="#맞춤형-또는-목록에-없는-프로바이더" aria-label="Permalink to &quot;맞춤형 또는 목록에 없는 프로바이더&quot;">​</a></h2><p>프로바이더가 온보딩에 목록에 없는 경우, <strong>Custom Provider</strong>를 선택하고 다음을 입력하십시오:</p><ul><li>API 호환성 모드 (OpenAI 호환, Anthropic 호환 또는 자동 감지)</li><li>기본 URL 및 API 키</li><li>모델 ID 및 선택적 별칭</li></ul><p>여러 맞춤형 엔드포인트가 공존할 수 있으며 — 각각 자체 엔드포인트 ID를 가집니다.</p>',20)])])}const b=a(n,[["render",s]]);export{g as __pageData,b as default};
